<template>
  <!-- Oh!I'm to lazy!I have only one component in Vue! -->
  <div id="app">
    <el-row type="flex" justify="center">
      <el-col :span="12">
        <el-date-picker v-model="item_date" placeholder="选择日期时间">
        </el-date-picker>
      </el-col>
      <el-col :span="12">
        <el-input v-model="item_title" placeholder="输入背诵标题" clearable></el-input>
      </el-col>
    </el-row>

    <el-row type="flex" justify="center">
      <el-col>
        <div>
          <el-input v-model="item_content" placeholder="输入背诵内容" clearable
            @keyup.enter.native="AddItem(item_date, Date.now(), item_title, item_content, NextTime(item_date, 1), NextTime(item_date, 2), NextTime(item_date, 4), NextTime(item_date, 7), NextTime(item_date, 15), NextTime(item_date, 30), NextTime(item_date, 91), NextTime(item_date, 183))"></el-input>
        </div>
      </el-col>
    </el-row>


    <el-row type="flex" justify="center">
      <el-col :span="96">
        <el-calendar v-model="calendar_data" :first-day-of-week="1"></el-calendar>
      </el-col>
    </el-row>


    <div v-for="item in items" :key="item.id">
      <div v-if="
          dateToTime(calendar_data) === dateToTime(item.date) || 
          dateToTime(calendar_data) === dateToTime(item.first) || 
          dateToTime(calendar_data) === dateToTime(item.second) || 
          dateToTime(calendar_data) === dateToTime(item.third) || 
          dateToTime(calendar_data) === dateToTime(item.forth) || 
          dateToTime(calendar_data) === dateToTime(item.fifth) || 
          dateToTime(calendar_data) === dateToTime(item.sixth) || 
          dateToTime(calendar_data) === dateToTime(item.seventh) || 
          dateToTime(calendar_data) === dateToTime(item.eighth)" class="items">
        <span v-if="item.title !== ''">{{ item.title }}<br/></span>
        <span v-if="item.content !== ''">{{ item.content }}</span>
      </div>
    </div>

  </div>
</template>

<script>

export default {
  name: 'App',
  data() {
    return {
      calendar_data: new Date(),
      item_date: '',
      item_title: '',
      item_content: '',
      items: ''
    }
  },
  mounted(){
    this.items = JSON.parse(localStorage.getItem('items'))===null||
                JSON.parse(localStorage.getItem('items'))===''||
                JSON.parse(localStorage.getItem('items'))===undefined?[]:JSON.parse(localStorage.getItem('items'))
    for (let i = 0; i < this.items.length; i++) {
      this.item[i]['date'] = new Date(this.item[i]['date']);
      this.item[i]['first'] = new Date(this.item[i]['first']);
      this.item[i]['second'] = new Date(this.item[i]['second']);
      this.item[i]['third'] = new Date(this.item[i]['third']);
      this.item[i]['forth'] = new Date(this.item[i]['forth']);
      this.item[i]['fifth'] = new Date(this.item[i]['fifth']);
      this.item[i]['sixth'] = new Date(this.item[i]['sixth']);
      this.item[i]['seventh'] = new Date(this.item[i]['seventh']);
      this.item[i]['eighth'] = new Date(this.item[i]['eighth']);
      
    }
  },
  methods: {
    AddItem(date, id, title, content, first, second, third, forth, fifth, sixth, seventh, eighth) {
      this.items.push({ date, id, title, content, first:new Date(first), second:new Date(second), third:new Date(third), forth:new Date(forth), fifth:new Date(fifth), sixth:new Date(sixth), seventh:new Date(seventh), eighth:new Date(eighth) })
      this.item_date = ''
      this.item_title = ''
      this.item_content = ''
    },
    NextTime(date, days) {
      return date.setDate(date.getDate()+ days)
    },
    dateToTime(olddate) {
      var date = new Date(olddate)
      let Y = date.getFullYear() + '-';
      let M = (date.getMonth() + 1 < 10 ? '0' + (date.getMonth() + 1) : date.getMonth() + 1) + '-';
      let D = (date.getDate()< 10 ? '0' + date.getDate(): date.getDate());
      return Y + M + D;
    },
    showDate(date){
      var newdate = new Date(date)
      newdate.setDate(-327)
      return newdate.toLocaleDateString()
    }
  },
  watch: {
    items: {
      handler(n) {
        // var n = []
        for (let i = 0; i < n.length; i++) {
          n[i]['date'] = new Date(n[i]['date']).getTime();
          n[i]['first'] = new Date(n[i]['first']).getTime();
          n[i]['second'] = new Date(n[i]['second']).getTime();
          n[i]['third'] = new Date(n[i]['third']).getTime();
          n[i]['forth'] = new Date(n[i]['forth']).getTime();
          n[i]['fifth'] = new Date(n[i]['fifth']).getTime();
          n[i]['sixth'] = new Date(n[i]['sixth']).getTime();
          n[i]['seventh'] = new Date(n[i]['seventh']).getTime();
          n[i]['eighth'] = new Date(n[i]['eighth']).getTime();
        }
        localStorage.setItem('items',JSON.stringify(n))
      },
      deep:true
    }
  }
}
</script>

<style>
.el-calendar {
  font-size: 14px;
}

.el-calendar-day {
  height: 35px !important;
  text-align: center;
}

* {
  padding: 0;
  margin: 0;
}

body {
  padding: 3px;
  background-color: #eee;
}

.items {
  border-radius: 4px;
  border: #DCDFE6 solid 1px;
  padding: 5px 10px;
  margin-top: 3px;
  margin-bottom: 3px;
  background-color: white;
}
</style>
